const input = $json ?? {};
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const content = buffer.toString('utf8');

const filepath = typeof input.path === 'string' && input.path.trim() !== '' ? input.path.trim() : '';

if (!filepath) {
  throw new Error('Missing filepath from local file trigger payload');
}

const filename = filepath.split('/').pop() || filepath;

const modifiedCandidates = [
  input.modifiedEpoch,
  input.mtimeMs,
  input.modified,
  input.lastModified,
  input.mtime,
  input.updatedAt,
  input.timestamp
];

let modifiedEpoch;
for (const candidate of modifiedCandidates) {
  if (candidate === undefined || candidate === null || candidate === '') {
    continue;
  }

  const numeric = Number(candidate);
  if (Number.isFinite(numeric) && numeric > 0) {
    modifiedEpoch = numeric > 9999999999 ? Math.floor(numeric / 1000) : Math.floor(numeric);
    break;
  }

  const parsed = Date.parse(String(candidate));
  if (Number.isFinite(parsed) && parsed > 0) {
    modifiedEpoch = Math.floor(parsed / 1000);
    break;
  }
}

const normalizedPath = filepath.replace(/\\/g, '/');
const projectMatch = normalizedPath.match(/^\/home\/node\/\.n8n-files\/openbrain\/inbox\/([^/]+)\/[^/]+$/);
const derivedProjectSlug = projectMatch ? projectMatch[1] : null;

return [{
  json: {
    filepath,
    filename,
    content,
    ...(modifiedEpoch !== undefined ? { modifiedEpoch } : {}),
    ...(derivedProjectSlug ? { project_slug: derivedProjectSlug } : {})
  }
}];

const base = $('Normalize File Payload').first().json;
const ingestResult = $json ?? {};

return [{
  json: {
    success: true,
    filepath: base.filepath,
    filename: base.filename,
    derivedProjectSlug: base.project_slug ?? null,
    ingestResult
  }
}];
